import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as t,o as d,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Модерация изображений и режим доступа","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Safety/image-moderation-and-access-mode.md","filePath":"ru-RU/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),o={name:"ru-RU/Safety/image-moderation-and-access-mode.md"};function r(n,e,s,m,p,h){return d(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="модерация-изображении-и-режим-доступа" tabindex="-1">Модерация изображений и режим доступа <a class="header-anchor" href="#модерация-изображении-и-режим-доступа" aria-label="Permalink to &quot;Модерация изображений и режим доступа&quot;">​</a></h1><p>Модерация изображений присваивает загруженным файлам возрастные рейтинги. Режим доступа определяет, какие рейтинги можно показывать через публичный доступ.</p><p>Это влияет на публичную галерею, публичные URL файлов и random image API. На админ-панель ограничение не распространяется: администраторы все равно могут просматривать и управлять всеми файлами.</p><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Откройте админ-панель и перейдите в:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Основные настройки:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="что-делает-access-mode" tabindex="-1">Что делает Access Mode <a class="header-anchor" href="#что-делает-access-mode" aria-label="Permalink to &quot;Что делает Access Mode&quot;">​</a></h2><p>Access mode определяет, какие возрастные рейтинги могут быть видимы публично.</p><p>Текущие режимы:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Публично видимые рейтинги</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Только General</td></tr></tbody></table><p>По умолчанию используется Adult mode.</p><p>Для приватных сайтов или сайтов с контентом для взрослых Adult mode может быть уместен. Для более осторожной публичной галереи выберите Youth, Teen или Child mode.</p><h2 id="что-дает-включение-модерации" tabindex="-1">Что дает включение модерации <a class="header-anchor" href="#что-дает-включение-модерации" aria-label="Permalink to &quot;Что дает включение модерации&quot;">​</a></h2><p>Когда модерация включена, ImgBed во время загрузки вызывает выбранного moderation provider и сохраняет определенный возрастной рейтинг.</p><p>Основные рейтинги:</p><table tabindex="0"><thead><tr><th>Рейтинг</th><th>Значение</th></tr></thead><tbody><tr><td>General</td><td>Безопасный публичный контент</td></tr><tr><td>R12</td><td>Слегка чувствительный контент</td></tr><tr><td>R16</td><td>Более чувствительный контент</td></tr><tr><td>R18</td><td>Контент для взрослых</td></tr></tbody></table><p>Результат модерации используется при определении публичного доступа.</p><p>Если модерация не включена или старые файлы не имеют рейтинга, такие файлы считаются unrated. Unrated-файлы не удаляются автоматически из публичной галереи или random image API только из-за отсутствия рейтинга.</p><h2 id="выбор-moderation-provider" tabindex="-1">Выбор moderation provider <a class="header-anchor" href="#выбор-moderation-provider" aria-label="Permalink to &quot;Выбор moderation provider&quot;">​</a></h2><p>Доступные провайдеры:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>У каждого провайдера свои требования:</p><ul><li>moderatecontent.com обычно требует API Key.</li><li>nsfwjs обычно требует API endpoint URL.</li><li>Sightengine требует API user и API secret.</li></ul><p>Выбирайте по своему аккаунту, доступности и качеству распознавания. Если модерация включена и настроена правильно, ImgBed пытается записать рейтинг изображения во время загрузки.</p><h2 id="влияние-на-публичную-галерею" tabindex="-1">Влияние на публичную галерею <a class="header-anchor" href="#влияние-на-публичную-галерею" aria-label="Permalink to &quot;Влияние на публичную галерею&quot;">​</a></h2><p>Публичная галерея фильтрует файлы по access mode.</p><p>Примеры:</p><ul><li>Adult mode: R18-изображения могут появляться.</li><li>Youth mode: R18-изображения скрыты.</li><li>Teen mode: R16 и R18 скрыты.</li><li>Child mode: показываются только General-изображения.</li></ul><p>Это влияет только на обычный публичный доступ. Админ-панель продолжает показывать все файлы.</p><h2 id="влияние-на-публичные-url-фаилов" tabindex="-1">Влияние на публичные URL файлов <a class="header-anchor" href="#влияние-на-публичные-url-фаилов" aria-label="Permalink to &quot;Влияние на публичные URL файлов&quot;">​</a></h2><p>Публичные URL файлов — это прямые ссылки на изображения, которые открывают посетители.</p><p>Если рейтинг файла разрешен текущим access mode, ImgBed возвращает исходное изображение.</p><p>Если рейтинг выше разрешенного уровня, обычный публичный доступ не возвращает исходное изображение. Вместо этого ImgBed возвращает настроенный blocked result или изображение-заглушку.</p><p>Пример:</p><ul><li>Текущий режим — Child mode.</li><li>Изображение имеет рейтинг R18.</li><li>Посетитель открывает публичный URL напрямую.</li><li>ImgBed не возвращает этому посетителю исходное R18-изображение.</li></ul><p><img src="'+a+'" alt="Ограниченное изображение файла" loading="lazy"></p><p>Администраторы, просматривающие файлы в админ-панели, этим ограничением не затрагиваются.</p><h2 id="влияние-на-random-image-api" tabindex="-1">Влияние на Random Image API <a class="header-anchor" href="#влияние-на-random-image-api" aria-label="Permalink to &quot;Влияние на Random Image API&quot;">​</a></h2><p>Random image API также фильтрует пул кандидатов по access mode.</p><p>В Child mode случайные изображения выбираются только из файлов с рейтингом General.</p><p>В Youth mode случайные изображения могут быть из General, R12 и R16, но не из R18.</p><p>Так random image API не обходит ограничения публичной галереи.</p><h2 id="связь-с-правилами-списков" tabindex="-1">Связь с правилами списков <a class="header-anchor" href="#связь-с-правилами-списков" aria-label="Permalink to &quot;Связь с правилами списков&quot;">​</a></h2><p>Access mode — не единственное правило публичного доступа. Он работает вместе с allow/block list rules.</p><p>Проще говоря:</p><ul><li>allowlisted-контент сначала считается публичным;</li><li>blocklisted-контент не может просматриваться напрямую обычными посетителями;</li><li>контент, которого нет ни в одном списке, затем проверяется по access mode.</li></ul><p>Если изображение ограничено и возрастным рейтингом, и правилами списков, обычные посетители все равно не смогут напрямую увидеть исходный файл.</p><h2 id="рекомендуемые-настроики" tabindex="-1">Рекомендуемые настройки <a class="header-anchor" href="#рекомендуемые-настроики" aria-label="Permalink to &quot;Рекомендуемые настройки&quot;">​</a></h2><p>Для публичных сайтов:</p><ul><li>Включите модерацию.</li><li>Выберите access mode по аудитории сайта.</li><li>Для посетителей любого возраста используйте Child mode или Teen mode.</li><li>Избегайте Adult mode, если не хотите показывать взрослый контент публично.</li><li>Просматривайте рейтинги файлов в админ-панели и при необходимости меняйте их вручную.</li></ul><p>Для приватных или личных сайтов:</p><ul><li>Adult mode обычно подходит.</li><li>Включите модерацию, если она полезна.</li><li>Просматривайте и корректируйте рейтинги в админ-панели по необходимости.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="исчезнут-ли-фаилы-из-админ-панели-после-смены-access-mode" tabindex="-1">Исчезнут ли файлы из админ-панели после смены Access Mode? <a class="header-anchor" href="#исчезнут-ли-фаилы-из-админ-панели-после-смены-access-mode" aria-label="Permalink to &quot;Исчезнут ли файлы из админ-панели после смены Access Mode?&quot;">​</a></h3><p>Нет.</p><p>Access mode влияет только на обычный публичный доступ. На админ-панель он не влияет.</p><h3 id="почему-после-перехода-на-child-mode-в-публичнои-галерее-стало-меньше-изображении" tabindex="-1">Почему после перехода на Child Mode в публичной галерее стало меньше изображений? <a class="header-anchor" href="#почему-после-перехода-на-child-mode-в-публичнои-галерее-стало-меньше-изображении" aria-label="Permalink to &quot;Почему после перехода на Child Mode в публичной галерее стало меньше изображений?&quot;">​</a></h3><p>Child mode позволяет публично показывать только файлы с рейтингом General. R12, R16 и R18 фильтруются.</p><h3 id="могут-ли-публичные-url-открывать-adult-images" tabindex="-1">Могут ли публичные URL открывать adult images? <a class="header-anchor" href="#могут-ли-публичные-url-открывать-adult-images" aria-label="Permalink to &quot;Могут ли публичные URL открывать adult images?&quot;">​</a></h3><p>Если текущий access mode не разрешает этот рейтинг, обычные публичные URL не возвращают исходное изображение.</p><h3 id="может-ли-random-image-api-вернуть-ограниченные-изображения" tabindex="-1">Может ли Random Image API вернуть ограниченные изображения? <a class="header-anchor" href="#может-ли-random-image-api-вернуть-ограниченные-изображения" aria-label="Permalink to &quot;Может ли Random Image API вернуть ограниченные изображения?&quot;">​</a></h3><p>Нет.</p><p>Random image API фильтрует кандидатов по текущему access mode.</p><h3 id="что-будет-со-старыми-unrated-images" tabindex="-1">Что будет со старыми unrated images? <a class="header-anchor" href="#что-будет-со-старыми-unrated-images" aria-label="Permalink to &quot;Что будет со старыми unrated images?&quot;">​</a></h3><p>Unrated-изображения не скрываются автоматически только из-за отсутствия результатов модерации. Их рейтинги можно позже изменить в админ-панели.</p>',67)])])}const g=t(o,[["render",r]]);export{b as __pageData,g as default};
